const input = $('Start Workflow').first().json;
const chunkText = input.chunk_text || '';
const systemPrompt = input.system_prompt || '';
const userPrompt = input.user_prompt || '';
const glossary = input.glossary || '';
const ragContext = input.rag_context || '';
const rollingSummary = input.rolling_summary || '';
const arcSummary = input.arc_summary || '';
const prevLine = input.prev_line || '';

let fullUserPrompt = '';
if (rollingSummary) fullUserPrompt += '## КРАТКОЕ СОДЕРЖАНИЕ ПРЕДЫДУЩЕЙ ГЛАВЫ:\n' + rollingSummary + '\n\n';
if (arcSummary) fullUserPrompt += '## КРАТКОЕ ОПИСАНИЕ ТЕКУЩЕЙ АРКИ:\n' + arcSummary + '\n\n';
if (prevLine) fullUserPrompt += '<CONTEXT_BEFORE>\n' + prevLine + '\n</CONTEXT_BEFORE>\n\n';
if (userPrompt) fullUserPrompt += userPrompt + '\n\n';
fullUserPrompt += '## ПЕРЕВЕДИ СТРОГО НА РУССКИЙ:\n' + chunkText;

let fullSystemPrompt = systemPrompt;
if (glossary) fullSystemPrompt = fullSystemPrompt.replace('{{GLOSSARY}}', '━━━━━━━━━━━━━━━━━━━━━━━━━━━\nГЛОССАРИЙ — ИСТОЧНИК ИСТИНЫ\n━━━━━━━━━━━━━━━━━━━━━━━━━━━\n' + glossary);
if (ragContext) fullSystemPrompt = fullSystemPrompt.replace('{{LIGHT_RAG}}', '━━━━━━━━━━━━━━━━━━━━━━━━━━━\nБАЗА ЗНАНИЙ МИРА (КОНТЕКСТ ИЗ RAG)\n━━━━━━━━━━━━━━━━━━━━━━━━━━━\n' + ragContext);
if (prevLine) fullSystemPrompt = fullSystemPrompt.replace('{{CONTEXT_BEFORE}}', '━━━━━━━━━━━━━━━━━━━━━━━━━━━\nСЕКЦИЯ<CONTEXT_BEFORE>\n━━━━━━━━━━━━━━━━━━━━━━━━━━━\nНЕ переводить.\nИспользовать только для улучшения связности основного текста.');

const modelConfig = input.model_config || { mainModel: 'ollama', mainModelName: 'llama3.2:3b', baseUrl: 'http://127.0.0.1:11434' };

return [{ json: { chunk_text: chunkText, system_prompt: fullSystemPrompt, user_prompt: fullUserPrompt, model_config: modelConfig, start_time: Date.now(), test_id: input.test_id || 'translation-core', attempt: 0 } }];

const input = $input.first().json;
console.log('🤖 Translation Core Start');
console.log('📝 Input: ' + input.chunk_text.length + ' chars');
console.log('🧠 Model: ' + input.model_config.mainModelName);
return $input.all();

const input = $input.first().json;
const output = input.output || '';
const hasContent = output.trim().length > 10;
const looksLikeKorean = /[ㄱ-ㅎㅏ-ㅣ가-힣]/.test(output);
if (!hasContent) return [{ json: { ...input, quality_check: 'empty', passed: false } }];
if (looksLikeKorean) return [{ json: { ...input, quality_check: 'still_korean', passed: false } }];
return [{ json: { ...input, quality_check: 'ok', passed: true } }];

const input = $input.first().json;
const output = input.output || '';
const forbiddenWords = ['그녀는', '그는', '했다', '말했다', '생각했다'];
const found = forbiddenWords.filter(w => output.includes(w));
return [{ json: { ...input, has_forbidden_words: found.length > 0, forbidden_words_found: found, passed_forbidden: found.length === 0 } }];

const input = $input.first().json;
const endTime = Date.now();
return [{ json: { success: true, output: input.output, model_used: input.model_config.mainModelName, model_type: input.model_config.mainModel, quality_check: input.quality_check, forbidden_words: input.forbidden_words_found || [], duration_ms: endTime - input.start_time, output_length: (input.output || '').length, input_length: (input.chunk_text || '').length, attempt: input.attempt + 1, test_id: input.test_id } }];
